export const Icon = ({
  name,
  filled = false,
  size = 20,
  color = "#16151C",
  activeColor = "#143888",
}) => {
  const icon = icons[name];

  if (!icon) return null;

  const paths = filled ? icon.fill : icon.outline;
  const strokeColor = filled ? activeColor : color;

  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 20 20"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
    >
      {React.Children.map(paths, (child) =>
        React.cloneElement(child, {
          stroke: strokeColor,
          fill: filled ? activeColor : "none",
          strokeWidth: 1.3,
          strokeLinecap: "round",
          strokeLinejoin: "round",
        })
      )}
    </svg>
  );
};


